      "content": "import type { ColorInput, HSL, HSV, RGB } from './types';\nexport declare class FastColor {\n    /**\n     * All FastColor objects are valid. So isValid is always true. This property is kept to be compatible with TinyColor.\n     */\n    isValid: boolean;\n    /**\n     * Red, R in RGB\n     */\n    r: number;\n    /**\n     * Green, G in RGB\n     */\n    g: number;\n    /**\n     * Blue, B in RGB\n     */\n    b: number;\n    /**\n     * Alpha/Opacity, A in RGBA/HSLA\n     */\n    a: number;\n    private _h?;\n    private _s?;\n    private _l?;\n    private _v?;\n    private _max?;\n    private _min?;\n    private _brightness?;\n    constructor(input: ColorInput);\n    setR(value: number): this;\n    setG(value: number): this;\n    setB(value: number): this;\n    setA(value: number): this;\n    setHue(value: number): this;\n    /**\n     * Returns the perceived luminance of a color, from 0-1.\n     * @see http://www.w3.org/TR/2008/REC-WCAG20-20081211/#relativeluminancedef\n     */\n    getLuminance(): number;\n    getHue(): number;\n    getSaturation(): number;\n    getLightness(): number;\n    getValue(): number;\n    /**\n     * Returns the perceived brightness of the color, from 0-255.\n     * Note: this is not the b of HSB\n     * @see http://www.w3.org/TR/AERT#color-contrast\n     */\n    getBrightness(): number;\n    darken(amount?: number): this;\n    lighten(amount?: number): this;\n    /**\n     * Mix the current color a given amount with another color, from 0 to 100.\n     * 0 means no mixing (return current color).\n     */\n    mix(input: ColorInput, amount?: number): this;\n    /**\n     * Mix the color with pure white, from 0 to 100.\n     * Providing 0 will do nothing, providing 100 will always return white.\n     */\n    tint(amount?: number): this;\n    /**\n     * Mix the color with pure black, from 0 to 100.\n     * Providing 0 will do nothing, providing 100 will always return black.\n     */\n    shade(amount?: number): this;\n    onBackground(background: ColorInput): this;\n    isDark(): boolean;\n    isLight(): boolean;\n    equals(other: FastColor): boolean;\n    clone(): this;\n    toHexString(): string;\n    /** CSS support color pattern */\n    toHsl(): HSL;\n    /** CSS support color pattern */\n    toHslString(): string;\n    /** Same as toHsb */\n    toHsv(): HSV;\n    toRgb(): RGB;\n    toRgbString(): string;\n    toString(): string;\n    /** Return a new FastColor object with one channel changed */\n    private _sc;\n    private _c;\n    private getMax;\n    private getMin;\n    private fromHexString;\n    private fromHsl;\n    private fromHsv;\n    private fromHsvString;\n    private fromHslString;\n    private fromRgbString;\n}\n",
