      "path": "/node_modules/antd/es/theme/interface/maps/size.d.ts",
      "content": "export interface SizeMapToken {\n    /**\n     * @nameZH XXL\n     * @default 48\n     */\n    sizeXXL: number;\n    /**\n     * @nameZH XL\n     * @default 32\n     */\n    sizeXL: number;\n    /**\n     * @nameZH LG\n     * @default 24\n     */\n    sizeLG: number;\n    /**\n     * @nameZH MD\n     * @default 20\n     */\n    sizeMD: number;\n    /** Same as size by default, but could be larger in compact mode */\n    sizeMS: number;\n    /**\n     * @nameZH 默认\n     * @desc 默认尺寸\n     * @default 16\n     */\n    size: number;\n    /**\n     * @nameZH SM\n     * @default 12\n     */\n    sizeSM: number;\n    /**\n     * @nameZH XS\n     * @default 8\n     */\n    sizeXS: number;\n    /**\n     * @nameZH XXS\n     * @default 4\n     */\n    sizeXXS: number;\n}\nexport interface HeightMapToken {\n    /** Only Used for control inside component like Multiple Select inner selection item */\n    /**\n     * @nameZH 更小的组件高度\n     * @nameEN XS component height\n     * @desc 更小的组件高度\n     * @descEN XS component height\n     */\n    controlHeightXS: number;\n    /**\n     * @nameZH 较小的组件高度\n     * @nameEN SM component height\n     * @desc 较小的组件高度\n     * @descEN SM component height\n     */\n    controlHeightSM: number;\n    /**\n     * @nameZH 较高的组件高度\n     * @nameEN LG component height\n     * @desc 较高的组件高度\n     * @descEN LG component height\n     */\n    controlHeightLG: number;\n}\n",
      "contentHash": "6ba4e948766fc8362480965e82d6a5b30ccc4fda4467f1389aba0dcff4137432"
