      "path": "/node_modules/dayjs/package.json",
      "content": "{\n  \"name\": \"dayjs\",\n  \"version\": \"1.11.13\",\n  \"description\": \"2KB immutable date time library alternative to Moment.js with the same modern API \",\n  \"main\": \"dayjs.min.js\",\n  \"types\": \"index.d.ts\",\n  \"scripts\": {\n    \"test\": \"TZ=Pacific/Auckland npm run test-tz && TZ=Europe/London npm run test-tz && TZ=America/Whitehorse npm run test-tz && npm run test-tz && jest\",\n    \"test-tz\": \"date && jest test/timezone.test --coverage=false\",\n    \"lint\": \"./node_modules/.bin/eslint src/* test/* build/*\",\n    \"prettier\": \"prettier --write \\\"docs/**/*.md\\\"\",\n    \"babel\": \"cross-env BABEL_ENV=build babel src --out-dir esm --copy-files && node build/esm\",\n    \"build\": \"cross-env BABEL_ENV=build node build && npm run size\",\n    \"sauce\": \"npx karma start karma.sauce.conf.js\",\n    \"test:sauce\": \"npm run sauce -- 0 && npm run sauce -- 1 && npm run sauce -- 2  && npm run sauce -- 3\",\n    \"size\": \"size-limit && gzip-size dayjs.min.js\"\n  },\n  \"pre-commit\": [\n    \"lint\"\n  ],\n  \"size-limit\": [\n    {\n      \"limit\": \"2.99 KB\",\n      \"path\": \"dayjs.min.js\"\n    }\n  ],\n  \"jest\": {\n    \"roots\": [\n      \"test\"\n    ],\n    \"testRegex\": \"test/(.*?/)?.*test.js$\",\n    \"testURL\": \"http://localhost\",\n    \"coverageDirectory\": \"./coverage/\",\n    \"collectCoverage\": true,\n    \"collectCoverageFrom\": [\n      \"src/**/*\"\n    ]\n  },\n  \"keywords\": [\n    \"dayjs\",\n    \"date\",\n    \"time\",\n    \"immutable\",\n    \"moment\"\n  ],\n  \"author\": \"iamkun\",\n  \"license\": \"MIT\",\n  \"homepage\": \"https://day.js.org\",\n  \"repository\": {\n    \"type\": \"git\",\n    \"url\": \"https://github.com/iamkun/dayjs.git\"\n  },\n  \"devDependencies\": {\n    \"@babel/cli\": \"^7.0.0-beta.44\",\n    \"@babel/core\": \"^7.0.0-beta.44\",\n    \"@babel/node\": \"^7.0.0-beta.44\",\n    \"@babel/preset-env\": \"^7.0.0-beta.44\",\n    \"babel-core\": \"^7.0.0-bridge.0\",\n    \"babel-jest\": \"^22.4.3\",\n    \"babel-plugin-external-helpers\": \"^6.22.0\",\n    \"cross-env\": \"^5.1.6\",\n    \"eslint\": \"^4.19.1\",\n    \"eslint-config-airbnb-base\": \"^12.1.0\",\n    \"eslint-plugin-import\": \"^2.10.0\",\n    \"eslint-plugin-jest\": \"^21.15.0\",\n    \"gzip-size-cli\": \"^2.1.0\",\n    \"jasmine-core\": \"^2.99.1\",\n    \"jest\": \"^22.4.3\",\n    \"karma\": \"^2.0.2\",\n    \"karma-jasmine\": \"^1.1.2\",\n    \"karma-sauce-launcher\": \"^1.1.0\",\n    \"mockdate\": \"^2.0.2\",\n    \"moment\": \"2.29.2\",\n    \"moment-timezone\": \"0.5.31\",\n    \"ncp\": \"^2.0.0\",\n    \"pre-commit\": \"^1.2.2\",\n    \"prettier\": \"^1.16.1\",\n    \"rollup\": \"^2.45.1\",\n    \"rollup-plugin-babel\": \"^4.4.0\",\n    \"rollup-plugin-terser\": \"^7.0.2\",\n    \"size-limit\": \"^0.18.0\",\n    \"typescript\": \"^2.8.3\"\n  }\n}\n",
