      "content": "{\n  \"name\": \"rc-tree-select\",\n  \"version\": \"5.27.0\",\n  \"description\": \"tree-select ui component for react\",\n  \"keywords\": [\n    \"react\",\n    \"react-component\",\n    \"react-tree-select\",\n    \"tree-select\"\n  ],\n  \"homepage\": \"https://github.com/react-component/tree-select\",\n  \"bugs\": {\n    \"url\": \"https://github.com/react-component/tree-select/issues\"\n  },\n  \"repository\": {\n    \"type\": \"git\",\n    \"url\": \"https://github.com/react-component/tree-select.git\"\n  },\n  \"license\": \"MIT\",\n  \"author\": \"smith3816@gmail.com\",\n  \"main\": \"./lib/index\",\n  \"module\": \"./es/index\",\n  \"files\": [\n    \"es\",\n    \"lib\",\n    \"dist\",\n    \"assets/*.less\",\n    \"assets/*.css\",\n    \"assets/*.png\",\n    \"assets/*.gif\"\n  ],\n  \"scripts\": {\n    \"build\": \"dumi build\",\n    \"compile\": \"father build\",\n    \"lint\": \"eslint src/ examples/ --ext .tsx,.ts,.jsx,.js\",\n    \"now-build\": \"npm run build\",\n    \"prepare\": \"husky && dumi setup\",\n    \"prepublishOnly\": \"npm run compile && np --yolo --no-publish --any-branch\",\n    \"prettier\": \"prettier '{src,tests}/**/*.{ts,tsx}' 'tests/**/*.js' --write\",\n    \"start\": \"dumi dev\",\n    \"test\": \"rc-test\"\n  },\n  \"lint-staged\": {\n    \"*\": \"prettier --write --ignore-unknown\"\n  },\n  \"dependencies\": {\n    \"@babel/runtime\": \"^7.25.7\",\n    \"classnames\": \"2.x\",\n    \"rc-select\": \"~14.16.2\",\n    \"rc-tree\": \"~5.13.0\",\n    \"rc-util\": \"^5.43.0\"\n  },\n  \"devDependencies\": {\n    \"@rc-component/father-plugin\": \"^1.1.0\",\n    \"@rc-component/trigger\": \"^1.18.3\",\n    \"@testing-library/react\": \"^12.1.5\",\n    \"@types/jest\": \"^29.5.13\",\n    \"@types/node\": \"^22.7.5\",\n    \"@types/react\": \"^18.3.11\",\n    \"@types/react-dom\": \"^19.0.1\",\n    \"@types/warning\": \"^3.0.3\",\n    \"@umijs/fabric\": \"^4.0.1\",\n    \"cheerio\": \"1.0.0-rc.12\",\n    \"cross-env\": \"^7.0.3\",\n    \"dumi\": \"^2.4.12\",\n    \"enzyme\": \"^3.11.0\",\n    \"enzyme-adapter-react-16\": \"^1.15.8\",\n    \"enzyme-to-json\": \"^3.6.2\",\n    \"eslint\": \"^8.57.1\",\n    \"eslint-plugin-jest\": \"^28.10.0\",\n    \"eslint-plugin-unicorn\": \"^56.0.0\",\n    \"father\": \"^4.5.0\",\n    \"glob\": \"^11.0.0\",\n    \"husky\": \"^9.1.6\",\n    \"lint-staged\": \"^15.2.10\",\n    \"np\": \"^10.0.7\",\n    \"prettier\": \"^3.3.3\",\n    \"rc-dialog\": \"^9.6.0\",\n    \"rc-field-form\": \"^2.4.0\",\n    \"rc-test\": \"^7.1.1\",\n    \"rc-virtual-list\": \"^3.14.8\",\n    \"react\": \"^16.0.0\",\n    \"react-dom\": \"^16.0.0\",\n    \"typescript\": \"^5.6.3\"\n  },\n  \"peerDependencies\": {\n    \"react\": \"*\",\n    \"react-dom\": \"*\"\n  }\n}\n",
